INSERT INTO `v1_868f36aa7c937d36a77f9eaf063b1cd41d0f445387c2d3b3bca7c2d8e9943916` VALUES (1, 1, 3, "スタンダードコレクション", "スタンダードコレクションではポスターやペナントなど\n部屋に飾れる定番グッズが盛りだくさん！\nあなたの部屋をカルミナで彩ろう！", "1回メダル{0}枚！\n定番グッズであなたの部屋をカルミナで彩ろう！");
INSERT INTO `v1_868f36aa7c937d36a77f9eaf063b1cd41d0f445387c2d3b3bca7c2d8e9943916` VALUES (1, 2, 10, "プレミアムコレクション", "プレミアムコレクションではサイン色紙や\nブロマイドなど、★★以上のグッズが盛りだくさん！\nレアグッズをたくさんゲットしよう！", "1回メダル{0}枚！\nメンバー直筆サイン色紙など、★★以上のグッズを確定でゲット！");
INSERT INTO `v1_868f36aa7c937d36a77f9eaf063b1cd41d0f445387c2d3b3bca7c2d8e9943916` VALUES (1, 3, 3, "フェスコレクション", "フェスコレクションではカルミナサマーライブで\n大活躍するグッズが勢ぞろい！\nゲットしたグッズを片手に、いざライブ会場へ！", "1回メダル{0}枚！\nカルミナライブに参加する際のマストアイテムをゲットしよう！");
